import { UmbTextStyles } from "@umbraco-cms/backoffice/style";
import {
  css,
  html,
  customElement,
  state,
  LitElement,
  when,
} from "@umbraco-cms/backoffice/external/lit";
import { UmbWorkspaceViewElement } from "@umbraco-cms/backoffice/workspace";
import { UmbElementMixin } from "@umbraco-cms/backoffice/element-api";
import type { FieldPreValueSource } from "@umbraco-forms/generated";
import { FORMS_PREVALUESOURCE_WORKSPACE_CONTEXT } from "../../prevaluesource-workspace.context-token.js";
import { DateTimeOptions } from "@umbraco-forms/entities";

const elementName = "workspace-view-prevaluesource-info";

@customElement(elementName)
export class UmbWorkspaceViewPrevalueSourceInfoElement
  extends UmbElementMixin(LitElement)
  implements UmbWorkspaceViewElement
{
  @state()
  _prevalueSource?: FieldPreValueSource;

  #workspaceContext?: typeof FORMS_PREVALUESOURCE_WORKSPACE_CONTEXT.TYPE;

  constructor() {
    super();

    this.consumeContext(FORMS_PREVALUESOURCE_WORKSPACE_CONTEXT, (instance) => {
      this.#workspaceContext = instance;
      this.#observePrevalueSource();
    });
  }

  #observePrevalueSource() {
    if (!this.#workspaceContext) return;

    this.observe(this.#workspaceContext.data, (prevalueSource) => {
      if (!prevalueSource) return;
      this._prevalueSource = prevalueSource;
    });
  }

  render() {
    return html`
      <uui-box headline=${this.localize.term("general_general")}>
        <umb-property-layout label="Id">
          <div slot="editor">${this._prevalueSource?.unique}</div>
        </umb-property-layout>
        ${when(!this.#workspaceContext?.getIsNew(),
          () => html`
            <umb-property-layout .label=${this.localize.term("content_createDate")}>
              <umb-localize-date
                slot="editor"
                .date=${this._prevalueSource?.created}
                .options=${DateTimeOptions}
              ></umb-localize-date>
            </umb-property-layout>
            ${when(this._prevalueSource?.createdBy,
              () => html`
                <umb-property-layout .label=${this.localize.term("content_createBy")}>
                  <div slot="editor">${this._prevalueSource?.createdByName}</div>
                </umb-property-layout>`)}
            <umb-property-layout .label=${this.localize.term("content_updateDate")}>
              <umb-localize-date
                slot="editor"
                .date=${this._prevalueSource?.updated}
                .options=${DateTimeOptions}
              ></umb-localize-date>
            </umb-property-layout>
            ${when(this._prevalueSource?.updatedBy,
              () => html`
                <umb-property-layout .label=${this.localize.term("content_updatedBy")}>
                  <div slot="editor">${this._prevalueSource?.updatedByName}</div>
                </umb-property-layout>`)}
          `)}
      </uui-box>`;
  }

  static styles = [
    UmbTextStyles,
		css`
			:host {
				display: block;
				padding: var(--uui-size-layout-1);
			}

      uui-box { margin-bottom: 20px }
		`,
  ];
}

export default UmbWorkspaceViewPrevalueSourceInfoElement;

declare global {
  interface HTMLElementTagNameMap {
    [elementName]: UmbWorkspaceViewPrevalueSourceInfoElement;
  }
}
